extra.modelCss:
/* Reset moderno + base profissional */

/* 1) Box sizing em tudo */
*, *::before, *::after {
  box-sizing: border-box;
}

/* 2) Remover margens padrão */
* {
  margin: 0;
}

/* 3) Base do body */
body {
  min-height: 100vh;
  line-height: 1.6;
}

/* 4) Imagens responsivas */
img {
  max-width: 100%;
  height: auto;
  display: block;
}

/* 5) Form controls herdarem fonte */
input, button, textarea, select {
  font: inherit;
}

/* 6) Evitar overflow por textos longos */
body {
  overflow-wrap: break-word;
}
